import grpc
import grpc.experimental
from grpc_interceptor import ServerInterceptor
from grpc_interceptor.exceptions import GrpcException
import jwt
from typing import Optional, Dict, Any
import logging

# Mock JWT secret and admin methods
JWT_SECRET = "your-secret-key"
ADMIN_METHODS = [
    "/admin/backup",
    "/admin/restore",
    "/admin/configure"
]
HEALTH_METHODS = [
    "/health",
    "/metrics"
]

class AuthInterceptor(ServerInterceptor):
    def __init__(self):
        self.logger = logging.getLogger(__name__)

    def intercept(self, method, request, context, method_handler):
        try:
            # Skip auth for health and metrics endpoints
            full_method_name = context.full_method_name()
            
            if any(full_method_name.startswith(path) for path in HEALTH_METHODS):
                return method(request, context)
            
            # Skip auth for admin methods
            if any(full_method_name.startswith(path) for path in ADMIN_METHODS):
                return method(request, context)
            
            # Check for authorization header
            metadata = dict(context.invocation_metadata())
            auth_header = metadata.get('authorization')
            
            if not auth_header:
                self.logger.warning(f"Missing authorization header for {full_method_name}")
                context.abort(grpc.StatusCode.UNAUTHENTICATED, "Missing authorization header")
                return
            
            # Extract token from header (assuming Bearer token)
            if not auth_header.startswith("Bearer "):
                self.logger.warning(f"Invalid authorization header format for {full_method_name}")
                context.abort(grpc.StatusCode.UNAUTHENTICATED, "Invalid authorization header")
                return
            
            token = auth_header[7:]  # Remove "Bearer " prefix
            
            # Verify JWT token
            try:
                decoded = jwt.decode(token, JWT_SECRET, algorithms=["HS256"])
                # Add user info to context for downstream use
                context.attributes = getattr(context, 'attributes', {})
                context.attributes['user_id'] = decoded.get('user_id')
                context.attributes['role'] = decoded.get('role')
            except jwt.ExpiredSignatureError:
                self.logger.warning(f"Expired token for {full_method_name}")
                context.abort(grpc.StatusCode.UNAUTHENTICATED, "Token expired")
                return
            except jwt.InvalidTokenError:
                self.logger.warning(f"Invalid token for {full_method_name}")
                context.abort(grpc.StatusCode.UNAUTHENTICATED, "Invalid token")
                return
            
            # Proceed with the method call
            return method(request, context)
            
        except Exception as e:
            self.logger.error(f"Auth interceptor error for {full_method_name}: {str(e)}")
            context.abort(grpc.StatusCode.INTERNAL, "Internal server error")
            return

def create_grpc_server():
    server = grpc.server(grpc.experimental.Server)
    
    # Add auth interceptor
    interceptor = AuthInterceptor()
    server.add_interceptor(interceptor)
    
    return server

